import React from 'react';
import PropTypes from 'prop-types';
import {platform, IOS, Group} from '@vkontakte/vkui';
import Panel from '@vkontakte/vkui/dist/components/Panel/Panel';
import PanelHeader from '@vkontakte/vkui/dist/components/PanelHeader/PanelHeader';
import HeaderButton from '@vkontakte/vkui/dist/components/HeaderButton/HeaderButton';
import Icon28ChevronBack from '@vkontakte/icons/dist/28/chevron_back';
import Icon24Back from '@vkontakte/icons/dist/24/back';
import Div from "@vkontakte/vkui/dist/es6/components/Div/Div";

const osName = platform();

const FullHistory = (props) => {
	const {id, go, gibddHistory, previewData} = props

	const getGibddHistoryDataArr = (object, name) => {
		let arr = []
		if (object) {
			for (let key in object) (
				arr.push(key)
			)
		}
		return arr.includes(name) && object[name] && object[name].length > 0
	}

	const getNamePreviewDataArr = (name) => {
		let arr = []
		if (previewData) {
			for (let key in previewData) (
				arr.push(key)
			)

		}
		return arr.includes(name) && previewData[name].length > 0
	}

	let wellDate = new Date();

	return <Panel id={id}>
		<PanelHeader
			left={<HeaderButton onClick={go} data-to="home">
				{osName === IOS ? <Icon28ChevronBack/> : <Icon24Back/>}
			</HeaderButton>}
		>
			Полная история
		</PanelHeader>
		<Group>

			<Div><a href='#'>Скачать отчет</a></Div>
			<br/>
			<Div><h1>{getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle,"model") && gibddHistory.history.gibdd_base.vehicle.model}{getNamePreviewDataArr(gibddHistory.history.gibdd_base.vehicle, "year") && ", " + gibddHistory.history.gibdd_base.vehicle.year}</h1></Div>
			<Div>{"Дата проверки  " + wellDate.toLocaleString("ru", {year: 'numeric', month: 'long', day: 'numeric'}) + "  "}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory, "VIN") && <strong>{"VIN: " + gibddHistory.VIN}</strong>}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory, "num") && <strong>{"Гос. номер: " + gibddHistory.num}</strong>}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory, "num") && <strong>{"СТС: " + gibddHistory.sts}</strong>}</Div>
			<Div>{getNamePreviewDataArr("image") && <img src={previewData.image} alt='photo' className='photo'/>}</Div>
			<Div>{getNamePreviewDataArr("category") && <span>{"Категория ТС: " + previewData.category + "  "}</span>}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle, "year") && <span>{"Год выпуска: " + gibddHistory.history.gibdd_base.vehicle.year}</span>}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle, "color") && <span>{"Цвет: " + gibddHistory.history.gibdd_base.vehicle.color}</span>}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle, "type") && <span>{"Тип кузова: " + gibddHistory.history.gibdd_base.vehicle.type}</span>}</Div>
			<Div>{getNamePreviewDataArr("capacity") ? <span>{"Объем двигателя: " + previewData.capacity + " куб. см"}</span> : getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle, "engine_volume") && <span>{"Объем двигателя: " + gibddHistory.history.gibdd_base.vehicle.engine_volume + " куб. см"}</span>}</Div>
			<Div>{getNamePreviewDataArr("power") ? <span>{"Мощность двигателя: " + previewData.power + " л.c."}</span> : getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle, "power_hp") && <span>{"Мощность двигателя: " + gibddHistory.history.gibdd_base.vehicle.power_hp + " л.c."}</span>}</Div>
			<Div>{getGibddHistoryDataArr(gibddHistory.history.gibdd_base.vehicle, "engine_number") && <span>{"№ двигателя: " + gibddHistory.history.gibdd_base.vehicle.engine_number}</span>}</Div>
			<Div>{getNamePreviewDataArr("engine_type") && <span>{"Тип двигателя: " + previewData.engine_type}</span>}</Div>
			<Div>{getNamePreviewDataArr("weight") && <span>{"Масса (без нагрузки/макс. разр.): " + previewData.weight}</span>}</Div>
			<Div>{getNamePreviewDataArr("wheel") && <span>{"Руль: " + previewData.wheel}</span>}</Div>
			<Div><p><strong>Фото</strong></p>{gibddHistory.imgs.status === 200 && gibddHistory.imgs.photo.length > 0 ? <div>
				{gibddHistory.imgs.photo.map((photo, index) => <div key={index}><img
					src={photo.src} alt='photo' className='photo'/> <p>{photo.date.length > 0 && photo.date}</p></div>)}
			</div> : <div>Фотографий не найдено</div>}</Div>
			<Div><p><strong>Объявления о продаже</strong></p>{gibddHistory.autoru.status === 200 && gibddHistory.autoru.bulletin_boards.length > 0 ? <div>
				{gibddHistory.autoru.bulletin_boards.map((bulletin_boards, index) => <div key={index}><p>{index + 1 }) {bulletin_boards.date.length > 0 && <span> {bulletin_boards.date}, </span>}  {bulletin_boards.model.length > 0 && <span> {bulletin_boards.model} г.в., </span>} {bulletin_boards.mileage.length > 0 && <span> {bulletin_boards.mileage}, </span>} {bulletin_boards.price.length > 0 && <span> {bulletin_boards.price}, </span>} {bulletin_boards.link.length > 0 && <a href={bulletin_boards.link}> {bulletin_boards.link} </a>}</p></div>)}
			</div> : <div>Объявлений не найдено</div>}</Div>



		</Group>
	</Panel>
}


export default FullHistory;
